import itertools

def are_isomorphic(graph1, graph2):
    n1 = len(graph1)
    n2 = len(graph2)

    if n1 != n2:
        return False

    num_edges1 = sum(len(adj) for adj in graph1.values())
    num_edges2 = sum(len(adj) for adj in graph2.values())
    if num_edges1 != num_edges2:
        return False

    keys1 = sorted(list(graph1.keys()))
    keys2 = sorted(list(graph2.keys()))

    for perm_keys2 in itertools.permutations(keys2):
        mapping = {}
        for i in range(n1):
            mapping[keys1[i]] = perm_keys2[i]

        is_current_permutation_isomorphism = True

        for u in keys1:
            mapped_u = mapping[u]

            neighbors_u_graph1 = graph1[u]
            expected_neighbors_mapped_u_graph2 = {mapping[v] for v in neighbors_u_graph1}

            actual_neighbors_mapped_u_graph2 = set(graph2.get(mapped_u, []))

            if expected_neighbors_mapped_u_graph2 != actual_neighbors_mapped_u_graph2:
                is_current_permutation_isomorphism = False
                break

        if is_current_permutation_isomorphism:
            return True

    return False
